/**
 * JsonRepairUtil — A utility to handle malformed JSON strings typically generated by LLMs.
 * 
 * LLMs often output JSON with:
 * 1. Unescaped control characters (like literal newlines inside strings).
 * 2. Unescaped double quotes inside strings.
 * 3. Truncated content (missing closing braces/brackets).
 */
export class JsonRepairUtil {
  /**
   * Attempts to repair and parse a potentially malformed JSON string.
   */
  static repairAndParse<T>(jsonStr: any): T {
    if (jsonStr === null || jsonStr === undefined) return {} as T;
    
    // If it's a Buffer (some DB drivers return TEXT as Buffer)
    if (Buffer.isBuffer(jsonStr)) {
      jsonStr = jsonStr.toString('utf8');
    }

    // If it's already an object (e.g. MySQL JSON column type), return it directly
    if (typeof jsonStr !== 'string') {
      return jsonStr as T;
    }

    let cleaned = jsonStr.trim();

    try {
      // First attempt: standard parse
      return JSON.parse(cleaned);
    } catch (e) {
      // Failed. Try to repair common issues.
      try {
        cleaned = this.repair(cleaned);
        return JSON.parse(cleaned);
      } catch (e2) {
        console.error('[JsonRepairUtil] Failed to repair JSON:', (e2 as Error).message);
        console.debug('[JsonRepairUtil] Original string:', jsonStr);
        throw e2;
      }
    }
  }

  /**
   * Main repair logic.
   */
  private static repair(str: string): string {
    let result = str;

    // 1. Handle literal newlines inside strings
    result = result.replace(/"([^"\\]*(?:\\.[^"\\]*)*)"/gs, (match) => {
      // Replace literal line breaks with escaped \n
      let cleaned = match.replace(/\n/g, '\\n').replace(/\r/g, '\\r');
      
      // Fix invalid escape sequences (like D:\code -> D:\\code)
      // We look for a \ that is NOT followed by " \ / b f n r t u
      cleaned = cleaned.replace(/\\(?!"|\\|\/|b|f|n|r|t|u[0-9a-fA-F]{4})/g, '\\\\');
      
      return cleaned;
    });

    // 2. Fix unescaped double quotes inside values (Experimental)
    // If we have something like "value": "It's "big"", we want "value": "It's \"big\""
    // This regex looks for double quotes that aren't preceded by a backslash AND aren't followed by , or } or ] or :
    // However, this can be risky. A safer way is to just handle the most common cases.

    // 3. Close truncated JSON
    result = this.closeTruncatedJson(result);

    return result;
  }

  /**
   * Attempts to close unbalanced braces/brackets for truncated LLM outputs.
   */
  private static closeTruncatedJson(str: string): string {
    const stack: string[] = [];
    let inString = false;
    let escaped = false;

    for (let i = 0; i < str.length; i++) {
      const char = str[i];

      if (escaped) {
        escaped = false;
        continue;
      }

      if (char === '\\') {
        escaped = true;
        continue;
      }

      if (char === '"') {
        inString = !inString;
        continue;
      }

      if (!inString) {
        if (char === '{' || char === '[') {
          stack.push(char);
        } else if (char === '}') {
          if (stack.length > 0 && stack[stack.length - 1] === '{') {
            stack.pop();
          }
        } else if (char === ']') {
          if (stack.length > 0 && stack[stack.length - 1] === '[') {
            stack.pop();
          }
        }
      }
    }

    let repaired = str;
    
    // If we are still in a string, close it
    if (inString) {
      repaired += '"';
    }

    // Close remaining structures in reverse order
    while (stack.length > 0) {
      const last = stack.pop();
      if (last === '{') repaired += '}';
      if (last === '[') repaired += ']';
    }

    return repaired;
  }
}
